// Build Context for AI Agent3 (Main Agent with Tools)
// FIXED: Preserve product_images and merge data from webhook + API response

// Get original webhook data (always has product_images)
const originalWebhook = $('Call Webhook1').item.json;

// Try to get API response data (has approved_design_url and updated design_variations)
let apiResponseData = null;
let usedApiResponse = false;

try {
  const apiCallData = $('Execute API Call1').all();
  if (apiCallData && apiCallData.length > 0) {
    apiResponseData = $('Execute API Call1').item.json;
    usedApiResponse = true;
  }
} catch (e) {
  // Execute API Call1 doesn't exist in this flow path
}

// Merge data: API response takes priority, but preserve fields from original webhook
const webhookData = {
  ...originalWebhook,  // Base data (has product_images, user_message, etc)
  ...(apiResponseData || {})  // Override with API response data if available
};

// Ensure product_images is preserved
if (!webhookData.product_images && originalWebhook.product_images) {
  webhookData.product_images = originalWebhook.product_images;
}

// Also handle single product_image field (backward compatibility)
if (!webhookData.product_images && originalWebhook.product_image) {
  webhookData.product_images = [originalWebhook.product_image];
}

if (!webhookData.design_variations && originalWebhook.design_variations) {
webhookData.design_variations=originalWebhook.design_variations;
}

const waData = $('WhatsApp Trigger2').first().json;
const waMsg = waData?.messages?.[0] || {};

// Extract key data
const jobId = webhookData.job_id;
const clientId = webhookData.client_id;
const phone = waMsg?.from || webhookData.phone;
const jobType = webhookData.job_type;

// Use next_step from API response if available
const currentStage = webhookData.next_step || webhookData.status;

const userText = waMsg?.text?.body || webhookData.user_message || '';
const productImages = webhookData.product_images || [];
const designVariations = webhookData.design_variations || [];


// // Build hints object
// const t = (userText || '').trim().toLowerCase();
// const hints = {
//   is_menu_choice: /^[1-5]$/.test(t),
//   is_approval_yes: ['yes', 'y', 'ok', 'approve', 'approved', 'موافق', 'תמם', 'כן', 'סבבה'].some(k => t.includes(k)),
//   is_approval_no: ['no', 'n', 'reject', 'change', 'לא', 'مش'].some(k => t.includes(k))
// };

// Build context object
const context = {
  job_id: jobId,
  client_id: clientId,
  phone: phone,
  job_type: jobType,
  current_stage: currentStage,
  user_text: userText,
  product_images: productImages,
  // design_variations: designVariations
};

// Add stage-specific data
if (currentStage === 'await_design_approval' || currentStage === 'generate_ad_copy' || currentStage === 'regenerate_or_edit_design') {
  context.design_variations = webhookData.design_variations || [];
  context.approved_design_index = webhookData.approved_design_index || 0;

  // For generate_ad_copy stage, add approved_design object
  if (currentStage === 'generate_ad_copy' && webhookData.design_variations && webhookData.design_variations.length > 0) {
    const approvedIndex = webhookData.approved_design_index || 0;

    // Prefer approved_design_url from API response
    const approvedDesignUrl = webhookData.approved_design_url || 
                             webhookData.design_variations[approvedIndex];

    // Ensure the approved URL is in the design_variations array
    if (approvedDesignUrl && !context.design_variations.includes(approvedDesignUrl)) {
      context.design_variations[approvedIndex] = approvedDesignUrl;
    }

    context.approved_design = {
      image_url: approvedDesignUrl,
      client_id: clientId,
      user_message: originalWebhook.user_message || webhookData.user_message || userText
    };
  }
}

if (currentStage === 'await_copy_approval' || currentStage === 'await_publish_approval') {
  context.ad_copy = webhookData.ad_copy || '';

  // Get approved design URL from either source
  const approvedDesignUrl = webhookData.approved_design_url || 
                           (webhookData.design_variations && webhookData.design_variations.length > 0 
                             ? webhookData.design_variations[webhookData.approved_design_index || 0] 
                             : '');

  context.image = approvedDesignUrl;

  // Also include design_variations array with approved URL
  if (webhookData.design_variations) {
    context.design_variations = webhookData.design_variations;
    const approvedIndex = webhookData.approved_design_index || 0;

    // Ensure approved URL is in the array
    if (approvedDesignUrl && !context.design_variations.includes(approvedDesignUrl)) {
      context.design_variations[approvedIndex] = approvedDesignUrl;
    }
  }
}

// Build the agent prompt - STRINGIFY IT!
const agentPrompt = JSON.stringify({
  context: context,
  user_text: userText,
  hints: $('Parse AI Decision1').first().json.hints,
  product_images: productImages,
  // Add stage-specific data at root level for easy access
  ...(context.approved_design ? { approved_design: context.approved_design } : {}),
  ...(context.ad_copy ? { ad_copy: context.ad_copy, image: context.image } : {}),
  // Include design_variations at root level for easy access
  ...(context.design_variations ? { design_variations: context.design_variations } : {})
});

return {
  json: {
    agent_prompt: agentPrompt,
    context: context,
    hints: $('Parse AI Decision1').first().json.hints,
    user_text: userText,
    product_images: productImages,
    raw_webhook: webhookData,
    raw_whatsapp: waData,
    used_api_response: usedApiResponse,  // Debug flag
    data_source: usedApiResponse ? 'merged' : 'webhook_only'  // Debug info
  }
};

// Parse AI Agent Output
// Converts the JSON string and prepares for backend saving

const item = $input.item.json;

// Get the output string
let outputStr = item.output;

// If output is already parsed, use it directly
if (typeof outputStr === 'object') {
  outputStr = JSON.stringify(outputStr);
}

// Strip markdown code blocks if present
if (typeof outputStr === 'string') {
  outputStr = outputStr.replace(/^```json\s*/i, '').replace(/\s*```$/, '').trim();
}

// Parse the JSON string
let parsed;
try {
  parsed = JSON.parse(outputStr);
} catch (e) {
  return [{
    json: {
      error: 'Failed to parse JSON',
      raw_output: outputStr,
      parse_error: e.message
    }
  }];
}

// Check if this is a tool call that returned data
const toolOutput = item.tool_output || null;

// If we have tool output and api_update with <TOOL_OUTPUT> placeholder, replace it
if (toolOutput && parsed.api_update?.payload) {
  const payload = parsed.api_update.payload;

  // Replace <TOOL_OUTPUT> with actual tool result
  for (const key in payload) {
    if (payload[key] === '<TOOL_OUTPUT>') {
      payload[key] = Array.isArray(toolOutput) ? toolOutput[0] : toolOutput;
    }
  }
}

// Flatten api_update for backend call
let flattenedApiUpdate = null;
if (parsed.api_update) {
  flattenedApiUpdate = {
    action: parsed.api_update.action,
    job_id: parsed.api_update.job_id || null,
    ...parsed.api_update.payload // Spread payload contents at the same level
  };

  // Parse design_variations if it's a JSON string
if (flattenedApiUpdate?.design_variations && typeof flattenedApiUpdate.design_variations === 'string') {
  try {
    const parsed = JSON.parse(flattenedApiUpdate.design_variations);
    flattenedApiUpdate.design_variations = Array.isArray(parsed) ? parsed.map(item => item.id || item) : [parsed.id || parsed];
  } catch (e) {
    // Keep as-is if parsing fails
  }
}

// Parse ad_copy if it's a JSON string
if (flattenedApiUpdate?.ad_copy && typeof flattenedApiUpdate.ad_copy === 'string') {
  try {
    const parsed = JSON.parse(flattenedApiUpdate.ad_copy);
    flattenedApiUpdate.ad_copy = Array.isArray(parsed) ? (parsed[0]?.id || parsed[0]) : (parsed.id || parsed);
  } catch (e) {
    // Keep as-is if parsing fails
  }
}

  // Remove job_id from the spread if it's already set (avoid duplication)
  if (flattenedApiUpdate.job_id) {
    delete flattenedApiUpdate.payload;
  }
}

// Extract and flatten all fields for easy access
return [{
  json: {
    // Top level fields
    step: parsed.step,
    reason: parsed.reason,
    tool: parsed.tool,
    whatsapp_message: parsed.whatsapp_message,
    image_generated: parsed.ImageGenerated || parsed.Imagegenerated || false,
    video_generated: parsed.videoGenerated || parsed.videoGenerated || false,

    // Tool inputs (flattened)
    tool_inputs: parsed.tool_inputs || null,

    // For Generate Design tool
    client_id: parsed.tool_inputs?.clientId || parsed.tool_inputs?.client_id || null,
    job_id: parsed.tool_inputs?.jobId || parsed.tool_inputs?.job_id || parsed.job_id || null,
    user_text: parsed.tool_inputs?.user_text || null,

    // For Generate Ad Copy tool
    image_url: parsed.tool_inputs?.image_url || null,
    design_prompt: parsed.tool_inputs?.design_prompt || null,
    user_message: parsed.tool_inputs?.user_message || null,

    // For Edit Image tool
    user_prompt: parsed.tool_inputs?.UserPrompt || parsed.tool_inputs?.prompt || null,
    image_id: parsed.tool_inputs?.ImageId || parsed.tool_inputs?.image_id || null,

    // Original api_update (nested)
    api_update_original: parsed.api_update || null,

    // Flattened api_update for HTTP call
    api_update: flattenedApiUpdate,

    // For backwards compatibility
    api_payload: parsed.api_update?.payload || null,
    api_action: parsed.api_update?.action || null,

    // Tool output for reference
    tool_output: toolOutput,

    // Keep original for debugging
    _original: parsed
  }
}];

