/**
 * CONTEXT BUILDER WITH INPUT STATE TRACKING
 */

const webhookData = $input.item.json;
const status = webhookData.status;
const nextStep = webhookData.next_step;
const jobType = webhookData.job_type;

// Get WhatsApp data
const waData = $('WhatsApp Trigger2').first().json;
const waMsg = waData?.messages?.[0] || {};
const userText = waMsg?.text?.body || '';
const messageType = waMsg?.type || 'text';
const phone = waMsg?.from || webhookData.phone;

// Check what inputs we have
const userMessage = webhookData.user_message || '';
const productImages = webhookData.product_images || [];
const hasText = !!(userMessage && userMessage.trim() && !['1','2','3','4','5'].includes(userMessage.trim()));
const hasImage = !!(productImages && productImages.length > 0);

// Build context
const context = {
  job_id: webhookData.job_id,
  client_id: webhookData.client_id,
  phone: phone,
  job_type: jobType,
  status: status,
  next_step: nextStep,
  user_message: userMessage,
  current_user_input: userText,
  product_images: productImages,
  message_type: messageType,
  has_text: hasText,
  has_image: hasImage
};

// Intent detection for approval stages
// const t = (userText || '').trim().toLowerCase();
// const approvalKeywords = ['yes', 'y', 'ok', 'approve', 'approved', 'موافق', 'תמם', 'כן', 'סבבה'];
// const rejectionKeywords = ['no', 'n', 'reject', 'change', 'לא', 'مش'];

// context.user_intent = {
//   is_approval: approvalKeywords.some(k => t.includes(k)),
//   is_approval_no: rejectionKeywords.some(k => t.includes(k)),
//   is_menu_choice: /^[1-5]$/.test(t.trim())
// };

const t = (userText || '').trim();

context.user_intent = {
  // ONLY menu detection stays here (since you said it's always menu)
  is_menu_choice: /^[1-5]$/.test(t),

  // Don't decide approval here, AI will decide:
  is_approval_yes: null,
  is_approval_no: null
};

// Add stage-specific data
if (nextStep === 'await_design_approval') {
  // User is reviewing design variations
  context.design_variations = webhookData.design_variations || [];
  context.approved_design_index = webhookData.approved_design_index || 0;

} else if (nextStep === 'generate_ad_copy') {
  // Design has been approved, now generate ad copy
  context.design_variations = webhookData.design_variations || [];
  context.approved_design_index = webhookData.approved_design_index || 0;

  const approvedIndex = webhookData.approved_design_index || 0;
  const approvedDesignUrl = webhookData.approved_design_url || 
                           (webhookData.design_variations && webhookData.design_variations.length > 0 
                             ? webhookData.design_variations[approvedIndex] 
                             : '');

  // Build approved_design object for AI Agent3
  context.approved_design = {
    image_url: approvedDesignUrl,
    client_id: webhookData.client_id,
    user_message: webhookData.user_message || userMessage
  };

} else if (nextStep === 'await_copy_approval') {
  // User is reviewing ad copy
  context.ad_copy = webhookData.ad_copy || '';

  const approvedDesignUrl = webhookData.approved_design_url || 
                           (webhookData.design_variations && webhookData.design_variations.length > 0 
                             ? webhookData.design_variations[webhookData.approved_design_index || 0] 
                             : '');

  context.approved_design_url = approvedDesignUrl;
  context.image = approvedDesignUrl;

} else if (nextStep === 'await_publish_approval') {
  // User is approving final publish
  context.ad_copy = webhookData.ad_copy || '';

  const approvedDesignUrl = webhookData.approved_design_url || 
                           (webhookData.design_variations && webhookData.design_variations.length > 0 
                             ? webhookData.design_variations[webhookData.approved_design_index || 0] 
                             : '');

  context.approved_design_url = approvedDesignUrl;
  context.image = approvedDesignUrl;
}

// Build AI prompt
const prompt = `You are the ADLY AI Agent - intelligent workflow orchestrator.

# CURRENT CONTEXT
${JSON.stringify(context, null, 2)}

# YOUR ROLE
Decide what to do based on job stage, inputs collected, and job type requirements.

# INPUT COLLECTION (CRITICAL - PREVENTS LOOPS)

## PRODUCT_SALE Requirements:
- MUST have: image + text
- Current state: has_image=${context.has_image}, has_text=${context.has_text}

#  (YOU MUST INFER)
You MUST analyze context.current_user_input and infer the user's intent.

Return  with EXACT schema:
"hints": 
{
  "is_menu_choice": boolean,
  "is_approval_yes": boolean,
  "is_approval_no": boolean,
}

 RULES:
- is_menu_choice = true ONLY if user input is exactly "1".."5".
- For await_design_approval:
  - if user clearly approves ("yes", "ok", "approve", "go ahead", "تمام", "موافق", "כן", etc.) -> is_approval_yes=true
  - if user rejects or asks changes ("no", "change", "not good", "مش", "لا", "לא", "بدّي تعديل", etc.) -> is_approval_no=true
  - if neither is clear -> is_unclear=true and ask a follow-up question
- Exactly one of (is_menu_choice, is_approval_yes, is_approval_no, is_unclear) should be true.


**Decision Tree For Product Sale Job:**
1. If has_image=false AND has_text=false:
   → Message: "Great! 🎨 Tell me about your products OR send images"
   → Action: null (wait for user input)
   → Lock: false

2. If has_image=true AND has_text=false:
   → Message: "Perfect! I received your image 📸\nNow tell me about your products (name, price, details)"
   → Action: null (wait for text)
   → Lock: false

3. If has_image=false AND has_text=true:
   → Message: "Great description! Now send me product images 📸"
   → Action: null (wait for image)
   → Lock: false

4. If has_image=true AND has_text=true:
   → Message: "⏳ Generating your design... (2-3 minutes)"
   → Action: save_input
   → Lock: true

## ANNOUNCEMENT Requirements:
- CAN work with: text only OR text + image
- Current state: has_image=${context.has_image}, has_text=${context.has_text}

**Decision Tree For Announcement Job:**
1. If has_image=false AND has_text=false:
   → Message: "Great! 🎨 Describe your announcement OR send an image"
   → Action: null
   → Lock: false

2. If has_image=true AND has_text=false:
   → Message: "Perfect! I received your image 📸\nNow describe what this announcement is about"
   → Action: null
   → Lock: false

3. If has_image=false AND has_text=true:
   → Analyze text: Does it describe something visual?
   → If mentions product/event/person: "Should I create a design or do you have an image?"
   → If generic announcement: Start processing
   → Message: "⏳ Generating your design..." (if starting)
   → Action: save_input (if starting)
   → Lock: true (if starting)

4. If has_image=true AND has_text=true:
   → Message: "⏳ Generating your design..."
   → Action: save_input
   → Lock: true

## REEL / CONTENT_STRATEGY / UGC_VIDEO:
- Usually text-only
- If has_text=true: Start immediately
- If has_text=false: Ask for description

# APPROVAL STAGES (After Input Collection Complete)

## await_design_approval:
- If hints.is_approval_yes true:
  → Action: approve_design
  → API body: {"action": "approve_design", "job_id": context.job_id, "approved_index": 0}
  → Message: "Perfect! ✅ Generating ad copy..."
  → Lock: true

- If hints.is_approval_no true:
  → Action: reject_design
  → API body: {"action": "reject_design", "job_id": context.job_id}
  → Message: "No problem! What changes would you like?"
  → Lock: true

## await_copy_approval:
- If hints.is_approval_yes true:
  → Action: approve_copy
  → Message: "Excellent! 📱 Ready to publish? Reply YES"
  → Lock: false

- If hints.is_approval_no true:
  → Action: reject_copy
  → Message: "What would you like to change in the text?"
  → Lock: true

## await_publish_approval:
- If hints.is_approval_yes true:
  → Action: approve_publish
  → Message: "Perfect! ✅ Publishing..."
  → Lock: true

- If hints.is_approval_no true:
  → Action: cancel_publish
  → Message: "No problem! Content saved."
  → Lock: false

# OUTPUT FORMAT
Return ONLY this JSON:
{
  "action": "save_input" | "approve_design" | "reject_design" | "approve_copy" | "reject_copy" | "approve_publish" | "cancel_publish" | null,
  "api_call": {
    "endpoint": "/api/jobs.php",
    "method": "POST",
    "body": {
      "action": "save_input",
      "job_id": "${context.job_id}",
      "user_message": "${context.user_message}",
      "advance": true
    }
  } | null,
  "hints": {
    "is_menu_choice": false | true,
    "is_approval_yes": true | true,
    "is_approval_no": false | true,
  },
  "whatsapp_message": "Message text" | null,
  "set_lock": true | false,
  "reasoning": "Your explanation"
}

RULES:
1. If action is null, set api_call to null (just asking for input)
2. Always provide whatsapp_message
3. Check has_image and has_text before deciding to process
4. For product_sale: MUST wait for both before save_input
5. Use context.job_id in all API calls
6. Return ONLY JSON, no markdown`;

return {
  json: {
    agent_prompt: prompt,
    context: context,
    raw_webhook: webhookData,
    raw_whatsapp: waData
  }
};

// Parse AI agent response
const aiResponse = $input.item.json;

let decision;
try {
  const output = aiResponse.output || aiResponse.text || JSON.stringify(aiResponse);

  const jsonMatch = output.match(/```json\s*([\s\S]*?)\s*```/);
  if (jsonMatch) {
    decision = JSON.parse(jsonMatch[1]);
  } else if (output.match(/^\s*\{/)) {
    decision = JSON.parse(output);
  } else {
    decision = JSON.parse(output);
  }
} catch (e) {
  console.error('Failed to parse AI response:', e);
  decision = {
    action: null,
    api_call: null,
    whatsapp_message: '⚠️ System error. Please try again.',
    set_lock: false,
    reasoning: 'Failed to parse AI response: ' + e.message
  };
}

// ---- Extract & normalize hints ----
const hints = (decision && typeof decision.hints === 'object' && decision.hints !== null)
  ? decision.hints
  : {
      is_menu_choice: false,
      is_approval_yes: false,
      is_approval_no: false
    };

const originalContext = $('Unified Context Builder1').item.json.context;

// Check if there's an API call
const hasApiCall = !!(decision.api_call && decision.api_call !== null && typeof decision.api_call === 'object' && Object.keys(decision.api_call).length > 0);

return {
  json: {
    ...decision,
    hints,
    original_context: originalContext,
    has_api_call: hasApiCall,
    raw_ai_response: aiResponse
  }
};

